#!/usr/bin/env python3
"""Heuristic exploration planner with utility-based greedy + BFS global planning."""
import os
import sys
import json
import argparse
import math
import random
from collections import deque

import numpy as np
from cogniplan_env import ExplorationEnv


def euclidean(a, b):
    return math.hypot(a[0] - b[0], a[1] - b[1])


class HeuristicPlanner:
    def __init__(self, epsilon=0.05, tabu_len=3):
        self.epsilon = epsilon
        self.tabu_len = tabu_len
        self.adj = None
        self.coord_to_idx = None
        self.nodes_list = None  # to keep reference length

    def build_graph(self, nodes):
        """Build static adjacency from nodes (list of dicts with 'coords' and 'neighbors')."""
        n = len(nodes)
        self.coord_to_idx = {}
        for i, nd in enumerate(nodes):
            coord = (nd['coords'][0], nd['coords'][1])
            self.coord_to_idx[coord] = i
        self.adj = [[] for _ in range(n)]
        for i, nd in enumerate(nodes):
            for nb_coord in nd.get('neighbors', []):
                nb_key = (nb_coord[0], nb_coord[1])
                if nb_key in self.coord_to_idx:
                    self.adj[i].append(self.coord_to_idx[nb_key])
        # make symmetric if needed but should be already

    def reset_episode(self, nodes):
        self.build_graph(nodes)

    def bfs_path(self, start_idx, target_idx):
        adj = self.adj
        n = len(adj)
        dist = [-1] * n
        parent = [-1] * n
        q = deque([start_idx])
        dist[start_idx] = 0
        while q:
            u = q.popleft()
            if u == target_idx:
                break
            for v in adj[u]:
                if dist[v] == -1:
                    dist[v] = dist[u] + 1
                    parent[v] = u
                    q.append(v)
        return dist, parent

    def reconstruct_path(self, start_idx, target_idx, parent):
        path = []
        curr = target_idx
        while curr != -1 and curr != start_idx:
            path.append(curr)
            curr = parent[curr]
        if curr == start_idx:
            path.reverse()
            return path
        return []

    def select_action(self, obs, curr_idx, prev_nodes):
        # prev_nodes: deque of recently visited node indices (tabu)
        neighbors = obs.get('neighbors', [])
        neighbor_idxs = []
        for nb in neighbors:
            key = (nb[0], nb[1])
            if key in self.coord_to_idx:
                neighbor_idxs.append(self.coord_to_idx[key])

        # Node utilities (updated each step)
        utilities = [n['utility'] for n in obs['nodes']]

        # Greedy: highest utility neighbor > 0, excluding tabu unless none
        best_util = -1
        best_nb = -1
        for ni in neighbor_idxs:
            if ni in prev_nodes:
                continue
            if utilities[ni] > best_util:
                best_util = utilities[ni]
                best_nb = ni
        if best_util > 0:
            return best_nb

        # No local good neighbor -> global planning
        # epsilon-greedy random neighbor
        if random.random() < self.epsilon and neighbor_idxs:
            valid = [ni for ni in neighbor_idxs if ni not in prev_nodes]
            if not valid:
                valid = neighbor_idxs
            return random.choice(valid)

        # Find globally highest utility node > 0
        max_util = -1
        global_best_idx = -1
        for i, u in enumerate(utilities):
            if u > max_util:
                max_util = u
                global_best_idx = i
        if max_util > 0:
            if global_best_idx == curr_idx:
                # Already at best, but no neighbor with utility>0; try to move anyway?
                # Fallback: any neighbor
                if neighbor_idxs:
                    return random.choice(neighbor_idxs)
                return -1
            # BFS
            _, parent = self.bfs_path(curr_idx, global_best_idx)
            path = self.reconstruct_path(curr_idx, global_best_idx, parent)
            if path:
                return path[0]
            else:
                # No path, maybe disconnected; try random neighbor
                if neighbor_idxs:
                    return random.choice(neighbor_idxs)
                return -1
        # No utility > 0 anywhere
        return -1


def run_episode(env, planner, max_steps=128):
    obs = env.reset()
    nodes = obs['nodes']
    planner.reset_episode(nodes)
    robot_pos = (float(obs['robot_pos'][0]), float(obs['robot_pos'][1]))

    # find closest start node
    min_d = float('inf')
    curr_idx = 0
    for coord, idx in planner.coord_to_idx.items():
        d = euclidean(coord, robot_pos)
        if d < min_d:
            min_d = d
            curr_idx = idx

    prev_nodes = deque(maxlen=planner.tabu_len)
    prev_nodes.append(curr_idx)

    for step in range(max_steps):
        next_idx = planner.select_action(obs, curr_idx, prev_nodes)
        if next_idx == -1:
            # No valid action -> end episode
            break
        target_coord = (nodes[next_idx]['coords'][0], nodes[next_idx]['coords'][1])
        obs, info = env.step(target_coord)
        curr_idx = next_idx
        prev_nodes.append(curr_idx)
        if info.get('done', False):
            break

    metrics = env.get_metrics()
    return {
        'explored_rate': float(metrics['explored_rate']),
        'travel_distance': float(metrics['travel_distance']),
        'success': bool(metrics['success']),
        'n_steps': int(metrics.get('n_steps', step))
    }


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', type=str, required=True)
    parser.add_argument('--checkpoint', type=str, required=True)  # not used
    parser.add_argument('--output', type=str, required=True)
    args = parser.parse_args()

    eval_config_path = os.path.join(args.data_path, 'eval_config.json')
    with open(eval_config_path, 'r') as f:
        eval_config = json.load(f)
    map_list = eval_config.get('maps', [])

    planner = HeuristicPlanner(epsilon=0.05, tabu_len=3)
    per_episode = []
    per_type = {}
    total_success = 0
    total_distance_succ = 0
    total_explored = 0
    n_episodes = 0

    for map_rel in map_list:
        map_path = os.path.join(args.data_path, 'maps_eval', map_rel)
        env_type = map_rel.split('/')[0]  # room, tunnel, outdoor
        env = ExplorationEnv(map_path=map_path)
        res = run_episode(env, planner)
        # Note: env may not have close method, do not call
        per_episode.append({
            'map_path': map_rel,
            'env_type': env_type,
            'success': 1 if res['success'] else 0,
            'travel_distance': res['travel_distance'],
            'explored_rate': res['explored_rate']
        })
        n_episodes += 1
        total_explored += res['explored_rate']
        if res['success']:
            total_success += 1
            total_distance_succ += res['travel_distance']
        # per_type aggregation
        if env_type not in per_type:
            per_type[env_type] = {'total': 0, 'success': 0, 'dist_sum': 0, 'expl_sum': 0}
        per_type[env_type]['total'] += 1
        per_type[env_type]['expl_sum'] += res['explored_rate']
        if res['success']:
            per_type[env_type]['success'] += 1
            per_type[env_type]['dist_sum'] += res['travel_distance']

    # Compute aggregates
    success_rate = total_success / n_episodes if n_episodes else 0
    explored_rate = total_explored / n_episodes if n_episodes else 0
    if total_success > 0:
        travel_distance = total_distance_succ / total_success
    else:
        travel_distance = 0.0

    per_type_out = {}
    for t, v in per_type.items():
        cnt = v['total']
        per_type_out[t] = {
            'explored_rate': v['expl_sum'] / cnt,
            'travel_distance': (v['dist_sum'] / v['success']) if v['success'] > 0 else 0.0,
            'success_rate': v['success'] / cnt
        }

    output = {
        'explored_rate': explored_rate,
        'travel_distance': travel_distance,
        'success_rate': success_rate,
        'per_episode': per_episode,
        'per_type': per_type_out,
        'total_episodes': n_episodes
    }
    with open(args.output, 'w') as f:
        json.dump(output, f, indent=2)


if __name__ == '__main__':
    main()
